import React, { memo } from 'react';
import FloatingCard from '../../../Components/FloatingCard/FloatingCard';
import { SectionSkillsContainer } from './SectionSkillsStyles';

const SectionSkills: React.FC = () => {
  return (
    <SectionSkillsContainer id="stacks">
      <FloatingCard
        imgSrc="/icons/front-end.svg"
        items={[
          'HTML | CSS | JAVASCRIPT',
          'SASS | BOOTSTRAP | MATERIALIZE',
          'FIGMA | ADOBEXD',
          'REACT & REDUX | ANGULAR'
        ]}
        title="FRONT-END"
      />
      <FloatingCard
        imgSrc="/icons/development.svg"
        items={['NODEJS WITH EXPRESS', 'ASP.NET', 'NestJS', 'MVC | WEB API']}
        title="BACK-END"
      />
      <FloatingCard
        imgSrc="/icons/database.svg"
        items={['MYSQL', 'MONGODB', 'POSTGRES', 'SQL SERVER']}
        title="DATABASE"
      />
      <FloatingCard
        imgSrc="/icons/deployment.svg"
        items={[
          'TRAVIS CI | JENKINS',
          'DOCKER | KUBERNETES',
          'AWS | GOOGLE CLOUD | HEROKU',
          'GIT & GITHUB'
        ]}
        title="DEVOPS"
      />
    </SectionSkillsContainer>
  );
};

export default memo(SectionSkills);
